<?php
namespace Tests\Feature\Admin\Content;use App\Models\Character;use App\Models\GameHomeCard;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class GameHomeCardAdminTest extends TestCase{use RefreshDatabase;private function data($overrides=[]){return array_merge(['name'=>'Admin card','code'=>'admin-card','destination_type'=>'route','destination_value'=>'world-maps.index','sort_order'=>50,'is_active'=>1,'opens_new_tab'=>0],$overrides);}public function test_admin_access_and_crud(){config(['game_admin.emails'=>['home-admin@example.test']]);$admin=User::factory()->create(['email'=>'home-admin@example.test']);$player=User::factory()->create();$this->actingAs($player)->get(route('admin.content.game-home-cards.index'))->assertForbidden();$this->actingAs($admin)->post(route('admin.content.game-home-cards.store'),$this->data())->assertRedirect();$card=GameHomeCard::where('code','admin-card')->firstOrFail();$this->get(route('admin.content.game-home-cards.index'))->assertOk()->assertSee('Admin card');$this->put(route('admin.content.game-home-cards.update',$card),$this->data(['name'=>'Edited','sort_order'=>60]))->assertRedirect();$this->patch(route('admin.content.game-home-cards.deactivate',$card))->assertRedirect();$this->assertFalse($card->fresh()->is_active);$this->delete(route('admin.content.game-home-cards.destroy',$card))->assertRedirect();$this->assertDatabaseMissing('game_home_cards',['id'=>$card->id]);}public function test_admin_cannot_choose_unapproved_route_or_manual_overview_value(){config(['game_admin.emails'=>['home-admin@example.test']]);$admin=User::factory()->create(['email'=>'home-admin@example.test']);$this->actingAs($admin)->post(route('admin.content.game-home-cards.store'),$this->data(['destination_value'=>'admin.content.items.index']))->assertSessionHasErrors('destination_value');$this->post(route('admin.content.game-home-cards.store'),$this->data(['code'=>'overview','destination_type'=>'active_character_overview','destination_value'=>'999']))->assertRedirect();$this->assertNull(GameHomeCard::where('code','overview')->firstOrFail()->destination_value);}public function test_route_edit_disables_external_url_validation_and_external_destinations_remain_validated(){config(['game_admin.emails'=>['home-admin@example.test']]);$admin=User::factory()->create(['email'=>'home-admin@example.test']);$card=GameHomeCard::create($this->data());$response=$this->actingAs($admin)->get(route('admin.content.game-home-cards.edit',$card));$response->assertOk()->assertSee('data-external-value value="world-maps.index" placeholder="https://example.com"  disabled ',false)->assertSee('externalInput.disabled=!isExternal',false)->assertSee('externalInput.required=isExternal',false)->assertSee('routeInput.required=isRoute',false);$this->put(route('admin.content.game-home-cards.update',$card),$this->data())->assertRedirect();$this->put(route('admin.content.game-home-cards.update',$card),$this->data(['destination_type'=>'external_url','destination_value'=>'https://example.com/game']))->assertRedirect();$this->put(route('admin.content.game-home-cards.update',$card),$this->data(['destination_type'=>'external_url','destination_value'=>'ftp://example.com']))->assertSessionHasErrors('destination_value');}}
